using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;
public class MyControl : UserControl
{
    private StatusStrip _statusStrip;

    public string DisplayName { get; set; }
    public int MaxItems { get; set; }

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9 changed the default ToolStrip rendering; set explicitly to
        // preserve the .NET 8 professional-style appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    /// <summary>
    /// Safely invokes DropDownControl, guarding against the null control that
    /// .NET 9 now rejects with ArgumentNullException.
    /// </summary>
    public static void ShowDropDown(
        IWindowsFormsEditorService editorService, Control? dropDown)
    {
        if (dropDown is null)
            return;

        editorService.DropDownControl(dropDown);
    }
}

